import React from 'react'
import { useState } from 'react';

const Content = () => {
  const[items,setItems]=useState([
    {id:1,activity:"Code Every Day",checked:true},
    {id:2,activity:"play cricket Every Day",checked:false},
    {id:3,activity:"Pratice Fluency",checked:false}])
    const handleChange = (id)=>{
      const changeItems =items.map(items => items.id==id ?{...items,checked:!items.checked}:items);
      setItems(changeItems);
    }
  return (
   <main>
    <ol>
      {items.map(items => (
        <li key={items.id}>
          <label>{items.activity}</label>
          <input type="checkbox" checked={items.checked} onChange={()=>handleChange(items.id)} />
          <button>Delete</button>
        </li>
      ))}
    </ol>
   </main>
  )
}

export default Content






